<div class="dashboard-grid limpieza-grid"><section class="hero-card gradient-lime"><div><span>Rutina diaria</span><h2>Checklist rápido, áreas claras y cero confusión.</h2><p>Turnos, pendientes y checklist en una vista compacta.</p></div><div class="hero-meter"><b><?= e($metrics['completas']) ?>/<?= e($metrics['total']) ?></b><small>completadas</small></div></section><div class="kpi-row"><div class="kpi-card"><i class="fa-solid fa-list-check"></i><span>Tareas hoy</span><b><?= e($metrics['total']) ?></b><small>Asignadas</small></div><div class="kpi-card violet"><i class="fa-solid fa-circle-check"></i><span>Completadas</span><b><?= e($metrics['completas']) ?></b><small>Actual</small></div><div class="kpi-card coral"><i class="fa-solid fa-triangle-exclamation"></i><span>Pendientes</span><b><?= e($metrics['pendientes']) ?></b><small>Revisar</small></div></div><section class="glass-card"><h3>Checklist de hoy</h3><?php foreach($check as $x): ?><div class="task-line <?= (int)$x['completado']?'done':'' ?>"><i class="fa-solid <?= (int)$x['completado']?'fa-circle-check':'fa-circle' ?>"></i><div><b><?= e($x['tarea']) ?></b><small><?= e($x['alberca']) ?> · <?= e($x['area']) ?> · <?= e(substr($x['hora_limite'],0,5)) ?></small></div></div><?php endforeach; ?></section><section class="glass-card"><h3>Turnos cercanos</h3><?php foreach($turnos as $x): ?><div class="catalog-line"><span><?= e($x['alberca']) ?> · <?= e($x['area']) ?></span><b><?= e(substr($x['hora_inicio'],0,5)) ?>-<?= e(substr($x['hora_fin'],0,5)) ?></b></div><?php endforeach; ?></section></div>
